/**
 * 손상차손처리
 */
scwin.f_AssetsImpairmentLossAndGain = async function () {
    //변경한 데이터가 있는지 체크한다.
    // if (ds_master.IsUpdated == false) {
    if (ds_master.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["데이타"]);
        return;
    }

    var nRow = ds_master.getMatchedIndex("chk", "1");
    if (nRow.length < 1) {
        await $c.gus.cfAlertMsg("선택한 내역이 존재하지 않습니다.");
        return;
    }

    for (var i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "chk") == "1") {
            if (ds_master.getCellData(i, "asetPatternClsCd") != "2") {
                await $c.gus.cfAlertMsg("무형자산만 입력이 가능합니다.");
                ds_master.setCellData(i, "chk", "0");
                gr_master.setFocusedCell(i, "chk");
                return false;
            }

            if ($c.gus.cfIsNull(ds_master.getCellData(i, "reappraiseDiffAmt")) || ds_master.getCellData(i, "reappraiseDiffAmt") == "0") {
                await $c.gus.cfAlertMsg("선택한 " + (i+1) + "번째 행의 손상차손/환입액을 입력하십시요");
                gr_master.setFocusedCell(i, "reappraiseDiffAmt", true);
                return;
            }

            if (ds_master.getCellData(i, "diffYyBookAmt") < 0) {
                await $c.gus.cfAlertMsg("손상차손/환입액은 현장부가액을 초과할 수 없습니다.");
                gr_master.setFocusedCell(i, "reappraiseDiffAmt", true);
                return;
            }

            if ($c.gus.cfIsNull(ds_master.getCellData(i, "mgntClntNo"))) {
                await $c.gus.cfAlertMsg("거래처를 입력해 주십시오");
                gr_master.setFocusedCell(i, "mgntClntNo");
                return;
            }
        }
    }

    let ret = await $c.gus.cfValidate([ica_chgHistDt]);
    if (!ret) {
        return;
    }

    if (await $c.win.confirm("손상차손/환입 처리 하시겠습니까?")) {
        // 고정자산이력구분코드(85 : 고정자산 손상차손/환입)
        for (var i=0; i < ds_master.getRowCount(); i++) {
            if (ds_master.getCellData(i, "chk") == "1") {
                ds_master.setCellData(i, "fixedAsetHistClsCd", scwin.isfixedAsetHistClsCd);
            }
        }
        ds_createAssets.setCellData(0, "histDt", ica_chgHistDt.getValue());
        sbm_saveLoss.userData1="noError";
        $c.sbm.execute(sbm_saveLoss);
    }
};

scwin.sbm_saveLoss_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        ds_master.reform();
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();
    }
};

scwin.sbm_saveLoss_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


